function _routerDeposit(
    address _router,
    address _vault,
    address _asset,
    uint _amount,
    string memory _memo
  ) internal {
    _vaultAllowance[msg.sender][_asset] -= _amount;
    safeApprove(_asset, _router, _amount);

    iROUTER(_router).depositWithExpiry(
      _vault,
      _asset,
      _amount,
      _memo,
      type(uint).max
    ); // Transfer by depositing
  }

function _routerDeposit(
    address _router,
    address _vault,
    address _asset,
    uint256 _amount,
    string memory _memo
) internal {
    _vaultAllowance[msg.sender][_asset] -= _amount;
    (bool success, ) = _asset.call(
        abi.encodeWithSignature(
            "approve(address,uint256)",
            _router,
            _amount
        )
    );
    require(success, "router deposit failed");
    IRouter(_router).depositWithExpiry(
        _vault,
        _asset,
        _amount,
        _memo,
        type(uint256).max
    );
}

function transferAllowance(
    address router,
    address newVault,
    address asset,
    uint amount,
    string memory memo
  ) external nonReentrant {
    if (router == address(this)) {
      _adjustAllowances(newVault, asset, amount);
      emit TransferAllowance(msg.sender, newVault, asset, amount, memo);
    } else {
      _routerDeposit(router, newVault, asset, amount, memo);
    }
  }
